// STM32 HAL
// ═══════════════════════════════════════════════════════════════════════════════
const stm32Hal = buildQuiz({
    series: "stm32-hal",
    title: "STM32 HAL",
    salt: "stm32-hal-26",
    totalParts: 18,
    questions: [
        { id: "sh-q001", part: 1, difficulty: "beginner", type: "mcq", question: "What does HAL stand for in STM32 development?", options: ["Hardware Access Layer", "Hardware Abstraction Layer", "High-level API Library", "Host Application Loader"], _answer: 1, explanation: "HAL (Hardware Abstraction Layer) provides portable API functions that abstract low-level register manipulation. Code written with HAL can be ported between STM32 families with minimal changes.", articleSlug: "stm32-hal-introduction", tags: ["HAL", "STM32", "fundamentals"] },
        { id: "sh-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "STM32 HAL drivers are more efficient (faster, less flash/RAM) than direct register access.", _answer: false, explanation: "HAL adds overhead: additional function calls, parameter checking, and abstraction layers. Direct register access (LL drivers or bare metal) is faster and smaller. HAL trades performance for portability and readability.", articleSlug: "stm32-hal-vs-ll", tags: ["HAL", "LL", "performance"] },
        { id: "sh-q003", part: 3, difficulty: "intermediate", type: "code-output", question: "What does this HAL call do?", code: "HAL_GPIO_WritePin(GPIOA, GPIO_PIN_5, GPIO_PIN_SET);", _answer: "sets PA5 high", acceptAlso: ["turns on PA5", "sets GPIOA pin 5 high", "LED on", "PA5 = 1"], explanation: "This sets GPIO port A, pin 5 to logic HIGH (3.3V). On Nucleo boards, PA5 is typically connected to the onboard LED (LD2). GPIO_PIN_RESET would set it LOW.", articleSlug: "stm32-hal-gpio", tags: ["GPIO", "output"] },
        { id: "sh-q004", part: 4, difficulty: "intermediate", type: "fill-blank", question: "In STM32CubeMX, the clock configuration tool ensures that peripheral clocks don't exceed the maximum ___ frequency.", _answer: "APB", acceptAlso: ["bus", "APB bus", "peripheral bus", "APB1/APB2"], explanation: "STM32 peripherals connect to APB1 (low-speed) and APB2 (high-speed) buses. CubeMX validates that prescaler settings keep bus clocks within safe limits (e.g., APB1 max 42MHz on STM32F4).", articleSlug: "stm32-hal-clock-configuration", tags: ["clock", "APB", "CubeMX"] },
        { id: "sh-q005", part: 5, difficulty: "advanced", type: "debug", question: "UART transmission works but reception always returns HAL_TIMEOUT. Find the issue:", code: "// UART2 init (CubeMX generated)\nhuart2.Instance = USART2;\nhuart2.Init.BaudRate = 115200;\nhuart2.Init.WordLength = UART_WORDLENGTH_8B;\nhuart2.Init.StopBits = UART_STOPBITS_1;\nhuart2.Init.Parity = UART_PARITY_NONE;\nHAL_UART_Init(&huart2);\n\n// Receive attempt\nuint8_t buf[10];\nHAL_UART_Receive(&huart2, buf, 10, 1000); // Always times out", options: ["RX pin not configured in GPIO alternate function (CubeMX pin assignment missing)", "Baud rate mismatch between sender and receiver", "Need to call HAL_UART_Receive_IT() instead for interrupt-based reception", "Buffer size too small — should be at least 64 bytes"], _answer: 0, explanation: "Most common STM32 UART receive failure: TX pin is configured but RX pin is not set as alternate function in GPIO init. CubeMX handles this if both TX and RX are assigned, but manual configuration often misses the RX pin's AF setting.", articleSlug: "stm32-hal-uart", tags: ["UART", "GPIO", "debugging"] },
        { id: "sh-q006", part: 6, difficulty: "advanced", type: "scenario", question: "Your STM32F4 project uses 95% of flash (1MB). A new feature requires 80KB more code. What's your optimization strategy?", scenario: { context: "Industrial controller. STM32F407 (1MB flash, 192KB RAM). Using HAL drivers for all peripherals.", metrics: { "Flash used": "950KB / 1024KB", "RAM used": "120KB / 192KB", "HAL drivers": "12 peripherals initialized" } }, options: ["Replace HAL with LL (Low-Level) drivers — saves 30-50% code size per peripheral", "Enable -Os compiler optimization and LTO (Link-Time Optimization)", "Move to a larger STM32 variant (STM32F427 with 2MB flash)", "Compress code sections and decompress at runtime"], _answer: 1, explanation: "Compiler optimization is the quickest win: -Os (optimize for size) + LTO (dead code elimination across translation units) typically saves 15-30% flash. If insufficient, selectively replace HAL with LL for the largest drivers. Hardware change is last resort.", articleSlug: "stm32-hal-optimization", tags: ["flash", "optimization", "LTO"] },
        { id: "sh-q007", part: 7, difficulty: "intermediate", type: "matching", question: "Match each STM32 peripheral to its typical use:", pairs: { left: ["TIM (Timer)", "ADC", "DMA", "I2C"], right: ["PWM generation, input capture, periodic interrupts", "Convert analog voltage to 12-bit digital value", "Transfer data without CPU intervention", "Communicate with sensors (accelerometer, temperature)"] }, _answer: [0, 1, 2, 3], explanation: "Timers: versatile (PWM, capture, counting). ADC: analog input (0-3.3V → 0-4095). DMA: offloads bulk transfers (ADC→memory, memory→UART). I2C: multi-device sensor bus.", articleSlug: "stm32-hal-peripherals", tags: ["Timer", "ADC", "DMA", "I2C"] },
        { id: "sh-q008", part: 8, difficulty: "advanced", type: "calculation", question: "An STM32 timer runs at 84MHz. You need a 50Hz PWM signal (20ms period) for servo control. What prescaler (PSC) and auto-reload (ARR) values work?", formula: "PWM_freq = Timer_clock / ((PSC+1) × (ARR+1))\n50 = 84,000,000 / ((PSC+1) × (ARR+1))", _answer: 83, unit: "PSC (with ARR=19999)", tolerance: 0, explanation: "50Hz = 84MHz / ((PSC+1)×(ARR+1)). Choose PSC=83: clock becomes 84M/84 = 1MHz. Then ARR = 1MHz/50Hz - 1 = 19999. Period = 20ms. For 1.5ms servo center: pulse = 1500 (CCR value).", articleSlug: "stm32-hal-timers-pwm", tags: ["PWM", "timer", "servo"] },
        { id: "sh-q009", part: 9, difficulty: "advanced", type: "ordering", question: "Arrange the STM32 startup sequence in correct order:", items: ["main() function called", "SystemInit() configures clock (HSE/PLL)", "Reset vector jumps to Reset_Handler", "HAL_Init() sets up SysTick and NVIC", "Stack pointer initialized from vector table"], _answer: ["Stack pointer initialized from vector table", "Reset vector jumps to Reset_Handler", "SystemInit() configures clock (HSE/PLL)", "HAL_Init() sets up SysTick and NVIC", "main() function called"], explanation: "STM32 boot: (1) Hardware loads SP from 0x00000000, (2) Fetches reset vector from 0x00000004, (3) Reset_Handler calls SystemInit (clock setup), (4) Calls __libc_init_array then main(), (5) In main(), HAL_Init() configures tick timer.", articleSlug: "stm32-hal-startup", tags: ["startup", "boot", "vector table"] },
        { id: "sh-q010", part: 10, difficulty: "advanced", type: "ethical", question: "Should STM32 firmware for medical/automotive devices be required to use formally verified HAL drivers instead of ST's standard HAL?", scenario: "ST's HAL has known errata and edge cases. Formally verified alternatives exist (SPARK/Ada, CompCert-compiled C) but are 5× more expensive to develop and maintain. Most safety-critical embedded systems rely on extensive testing instead.", options: [{ label: "Require formal verification for all safety-critical firmware", framework: "Maximum safety — eliminate classes of bugs mathematically" }, { label: "Testing + code review is sufficient with proper processes (DO-178C, IEC 62304)", framework: "Industry standard — proven process is adequate" }, { label: "Verify critical paths only (interrupt handlers, state machines), test the rest", framework: "Proportional — verify where failure is catastrophic" }, { label: "Use ST's HAL as-is but add extensive runtime checks and watchdogs", framework: "Defense in depth — detect and recover from bugs at runtime" }], _answer: 2, explanation: "Proportional verification is the pragmatic approach: formally verify the scheduler, interrupt handlers, and safety-critical state machines. Test everything else thoroughly. Full verification is prohibitively expensive for 100K+ lines of HAL.", articleSlug: "stm32-hal-safety", tags: ["safety", "verification", "medical"] }
    ]
});

