// USB DEVELOPMENT
// ═══════════════════════════════════════════════════════════════════════════════
const usbDev = buildQuiz({
    series: "usb-dev",
    title: "USB Development",
    salt: "usb-dev-2026",
    totalParts: 17,
    questions: [
        { id: "usb-q001", part: 1, difficulty: "beginner", type: "mcq", question: "What is the maximum data rate of USB 2.0 High Speed?", options: ["12 Mbps", "480 Mbps", "5 Gbps", "10 Gbps"], _answer: 1, explanation: "USB 2.0 High Speed: 480 Mbps. Full Speed: 12 Mbps. Low Speed: 1.5 Mbps. USB 3.0 (SuperSpeed): 5 Gbps. USB 3.2 Gen2: 10 Gbps. USB4: 40 Gbps.", articleSlug: "usb-dev-fundamentals", tags: ["USB 2.0", "speed"] },
        { id: "usb-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "A USB device can have multiple configurations active simultaneously.", _answer: false, explanation: "A USB device can have multiple configurations defined, but only ONE can be active at a time. The host selects a configuration via SET_CONFIGURATION request. Each configuration can have multiple interfaces (composite device).", articleSlug: "usb-dev-descriptors", tags: ["configuration", "descriptors"] },
        { id: "usb-q003", part: 3, difficulty: "intermediate", type: "ordering", question: "Arrange the USB enumeration process in correct order:", items: ["Host reads device descriptor (address 0)", "Device assigned unique address (SET_ADDRESS)", "Host selects configuration (SET_CONFIGURATION)", "Device connects and hub detects speed", "Host reads full descriptors (config, interface, endpoint)"], _answer: ["Device connects and hub detects speed", "Host reads device descriptor (address 0)", "Device assigned unique address (SET_ADDRESS)", "Host reads full descriptors (config, interface, endpoint)", "Host selects configuration (SET_CONFIGURATION)"], explanation: "Enumeration: connect→speed detect→get device descriptor (8 bytes at addr 0)→assign address→get full descriptors→select configuration→device ready. All via control endpoint 0.", articleSlug: "usb-dev-enumeration", tags: ["enumeration", "setup"] },
        { id: "usb-q004", part: 4, difficulty: "intermediate", type: "fill-blank", question: "USB transfers data in units called ___, which have a maximum size depending on speed and endpoint type.", _answer: "packets", acceptAlso: ["transactions", "data packets"], explanation: "USB data travels in packets. Max packet sizes: Control EP0: 64B (HS). Bulk: 512B (HS). Interrupt: 1024B (HS). Isochronous: 1024B (HS). These sizes are defined in endpoint descriptors.", articleSlug: "usb-dev-transfers", tags: ["packets", "endpoints"] },
        { id: "usb-q005", part: 5, difficulty: "advanced", type: "matching", question: "Match each USB transfer type to its ideal use case:", pairs: { left: ["Control transfers", "Bulk transfers", "Interrupt transfers", "Isochronous transfers"], right: ["Device configuration and standard requests", "Mass storage (reliable, no timing guarantee)", "HID devices — keyboard, mouse (small, periodic, guaranteed latency)", "Audio/video streaming (timing-guaranteed, no retransmission)"] }, _answer: [0, 1, 2, 3], explanation: "Control: setup/config. Bulk: large reliable data (disks, printers). Interrupt: small guaranteed-latency (HID). Isochronous: real-time streams (audio/video) — tolerates loss but not delay.", articleSlug: "usb-dev-transfer-types", tags: ["transfer types", "endpoints"] },
        { id: "usb-q006", part: 6, difficulty: "advanced", type: "debug", question: "A custom USB HID device enumerates but the host never receives input reports. Find the issue:", code: "// HID Report Descriptor (simplified)\n0x05, 0x01,   // Usage Page (Generic Desktop)\n0x09, 0x06,   // Usage (Keyboard)\n0xA1, 0x01,   // Collection (Application)\n0x05, 0x07,   //   Usage Page (Keyboard/Keypad)\n0x19, 0xE0,   //   Usage Min (Left Ctrl)\n0x29, 0xE7,   //   Usage Max (Right GUI)\n0x15, 0x00,   //   Logical Min (0)\n0x25, 0x01,   //   Logical Max (1)\n0x75, 0x01,   //   Report Size (1 bit)\n0x95, 0x08,   //   Report Count (8)\n0x81, 0x02,   //   Input (Variable)\n0xC0          // End Collection\n\n// Endpoint: IN EP1, bInterval=10ms, wMaxPacketSize=8", options: ["Report descriptor is correct but firmware never calls USB_Send on EP1", "bInterval=10ms is too slow — host polls too infrequently", "Missing Output report definition — host won't communicate without bidirectional support", "wMaxPacketSize=8 doesn't match report size (1 byte)"], _answer: 0, explanation: "The descriptor is valid and endpoint is configured. The most common issue: firmware initializes USB but never actually sends data on the IN endpoint. The host polls EP1 every 10ms but the device NAKs because no data is queued. Fix: call the send function in the main loop or timer ISR.", articleSlug: "usb-dev-hid", tags: ["HID", "debugging", "IN endpoint"] },
        { id: "usb-q007", part: 7, difficulty: "advanced", type: "scenario", question: "You're designing a USB audio device (microphone). Users report audio dropouts every 30 seconds. What's the most likely cause?", scenario: { context: "USB Audio Class 1.0 device. 48kHz, 16-bit mono. Isochronous endpoint, 1ms interval.", metrics: { "Dropout duration": "~2ms gap", "Frequency": "every 30±5 seconds", "Host OS": "Windows 10", "USB bus load": "45%" } }, options: ["Host USB scheduler deprioritizes isochronous during periodic housekeeping (1024-frame microframe scheduling)", "Audio clock drift — device sample rate slightly off from host clock, buffer underrun when difference accumulates", "USB bandwidth exceeded periodically by other devices", "Windows audio stack buffer too small"], _answer: 1, explanation: "Clock drift is the #1 cause of periodic USB audio dropouts. If the device crystal is 47,998Hz instead of 48,000Hz, the buffer empties by 2 samples/second. After 30s: 60 samples deficit = underrun. Fix: adaptive synchronization (feedback endpoint) or async mode.", articleSlug: "usb-dev-audio", tags: ["audio", "isochronous", "clock drift"] },
        { id: "usb-q008", part: 8, difficulty: "advanced", type: "calculation", question: "A USB 2.0 bulk endpoint with 512-byte max packet size needs to transfer a 10KB file. How many transactions (minimum)?", formula: "Transactions = ceil(data_size / max_packet_size) + ZLP_if_needed", _answer: 20, unit: "transactions", tolerance: 0, explanation: "10,240 bytes / 512 bytes = exactly 20 packets. Since 10KB is an exact multiple of 512, a Zero Length Packet (ZLP) is needed to signal end-of-transfer — so 21 transactions total. Without ZLP: 20 if the host knows the expected size.", articleSlug: "usb-dev-bulk-transfer", tags: ["bulk", "transactions", "ZLP"] },
        { id: "usb-q009", part: 9, difficulty: "intermediate", type: "mcq", question: "What USB class code is used for Communication Devices (serial ports, modems)?", options: ["0x01 (Audio)", "0x02 (CDC - Communications Device Class)", "0x03 (HID)", "0x08 (Mass Storage)"], _answer: 1, explanation: "CDC (class 0x02) is used for virtual serial ports (USB-to-UART bridges), modems, and network adapters. It's the most common way to add serial communication to USB devices (CDC-ACM subclass).", articleSlug: "usb-dev-cdc", tags: ["CDC", "serial", "class codes"] },
        { id: "usb-q010", part: 10, difficulty: "advanced", type: "ethical", question: "Should USB devices be allowed to present as a different device class than they actually are (e.g., a 'USB drive' that's actually a keyboard injecting keystrokes)?", scenario: "BadUSB attack: a malicious USB stick presents as a HID keyboard, typing commands to compromise the host. The USB spec has no authentication mechanism to verify device identity. Defenses exist (USB firewall software) but aren't standard.", options: [{ label: "USB spec should require cryptographic device authentication", framework: "Security by design — prevent the attack class entirely" }, { label: "No change needed — physical access to USB port implies trust", framework: "Physical security — if they can plug in, game over anyway" }, { label: "OS should prompt user to confirm new device types (like Bluetooth pairing)", framework: "User consent — explicit approval for each device class" }, { label: "Enterprise policy: only allow pre-approved USB device VID/PIDs", framework: "Allowlisting — corporate control" }], _answer: 2, explanation: "User confirmation for new device types (already implemented in ChromeOS, partially in macOS) balances usability and security. First time a 'keyboard' appears from a USB port, prompt: 'A keyboard was connected. Allow?' This stops BadUSB attacks without breaking legitimate devices.", articleSlug: "usb-dev-security", tags: ["BadUSB", "security", "authentication"] }
    ]
});

// ═══════════════════════════════════════════════════════════════════════════════
// UNITY GAME ENGINE
// ═══════════════════════════════════════════════════════════════════════════════
const unityGameEngine = buildQuiz({
    series: "unity-game-engine",
    title: "Unity Game Engine",
    salt: "unity-eng-26",
    totalParts: 16,
    questions: [
        { id: "uge-q001", part: 1, difficulty: "beginner", type: "mcq", question: "In Unity, what component must every GameObject have?", options: ["Rigidbody", "Collider", "Transform", "MeshRenderer"], _answer: 2, explanation: "Every GameObject has a Transform component (position, rotation, scale). It cannot be removed. Rigidbody, Collider, and Renderer are optional components added as needed.", articleSlug: "unity-game-engine-fundamentals", tags: ["Transform", "GameObject"] },
        { id: "uge-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "Update() and FixedUpdate() are called at the same rate in Unity.", _answer: false, explanation: "Update() is called every frame (variable rate, depends on FPS). FixedUpdate() is called at a fixed interval (default 0.02s = 50Hz) regardless of frame rate. Physics code should go in FixedUpdate() for deterministic behavior.", articleSlug: "unity-game-engine-lifecycle", tags: ["Update", "FixedUpdate", "lifecycle"] },
        { id: "uge-q003", part: 3, difficulty: "intermediate", type: "code-output", question: "What does this Unity C# code do?", code: "void Update() {\n    transform.Translate(Vector3.forward * 5f * Time.deltaTime);\n}", _answer: "moves the object forward at 5 units per second", acceptAlso: ["moves forward", "constant forward movement", "5 units/second forward"], explanation: "transform.Translate moves the object. Vector3.forward = (0,0,1). Multiplying by Time.deltaTime makes it frame-rate independent: 5 units per second regardless of FPS. Without deltaTime, speed would vary with frame rate.", articleSlug: "unity-game-engine-movement", tags: ["movement", "deltaTime"] },
        { id: "uge-q004", part: 4, difficulty: "intermediate", type: "fill-blank", question: "In Unity, ___ are reusable templates for creating GameObjects at runtime.", _answer: "Prefabs", acceptAlso: ["prefabs", "prefab"], explanation: "Prefabs are pre-configured GameObject templates stored as assets. Instantiate() creates copies at runtime. Changes to the prefab asset propagate to all instances. Essential for bullets, enemies, pickups — anything spawned dynamically.", articleSlug: "unity-game-engine-prefabs", tags: ["Prefabs", "Instantiate"] },
        { id: "uge-q005", part: 5, difficulty: "advanced", type: "debug", question: "A Unity character passes through walls despite having a Rigidbody and BoxCollider. What's the bug?", code: "// Player movement script\nvoid Update() {\n    float h = Input.GetAxis(\"Horizontal\");\n    float v = Input.GetAxis(\"Vertical\");\n    transform.position += new Vector3(h, 0, v) * speed * Time.deltaTime;\n}", options: ["Moving via transform.position bypasses physics — collisions are ignored", "BoxCollider needs isTrigger = false (might be checked)", "Rigidbody needs isKinematic = false", "speed is too high — object tunnels through thin walls"], _answer: 0, explanation: "Directly setting transform.position teleports the object, bypassing the physics engine. Colliders only respond to physics-driven movement. Fix: use Rigidbody.MovePosition() or rb.velocity for physics-aware movement. This is the #1 Unity physics bug.", articleSlug: "unity-game-engine-physics", tags: ["physics", "Rigidbody", "collision"] },
        { id: "uge-q006", part: 6, difficulty: "advanced", type: "scenario", question: "Your Unity mobile game targets 60fps but drops to 30fps during combat (20 enemies on screen). Profiler shows GC spikes. What's the fix?", scenario: { context: "Unity 2022, IL2CPP build. Combat spawns enemies, each firing projectiles every 0.5s.", metrics: { "GC allocs": "2.5MB/frame during combat", "Main culprits": "Instantiate() and string concatenation in UI", "Object count": "200+ active projectiles" } }, options: ["Object pooling — pre-instantiate projectiles and enemies, recycle instead of Instantiate/Destroy", "Reduce enemy count to 10", "Use Burst compiler for all scripts", "Increase quality settings target frame rate"], _answer: 0, explanation: "Object pooling eliminates GC by recycling objects instead of creating/destroying them. Pre-allocate pools at level start. On 'spawn': enable a pooled object. On 'destroy': disable and return to pool. Eliminates the 2.5MB/frame allocation.", articleSlug: "unity-game-engine-optimization", tags: ["pooling", "GC", "performance"] },
        { id: "uge-q007", part: 7, difficulty: "intermediate", type: "ordering", question: "Arrange Unity's script lifecycle methods in execution order:", items: ["Update()", "Awake()", "Start()", "LateUpdate()", "OnEnable()"], _answer: ["Awake()", "OnEnable()", "Start()", "Update()", "LateUpdate()"], explanation: "Unity lifecycle: Awake (first, even if disabled) → OnEnable (when activated) → Start (before first Update, once) → Update (every frame) → LateUpdate (after all Updates, good for camera follow).", articleSlug: "unity-game-engine-lifecycle", tags: ["lifecycle", "execution order"] },
        { id: "uge-q008", part: 8, difficulty: "advanced", type: "matching", question: "Match each Unity system to its purpose:", pairs: { left: ["ScriptableObject", "Addressables", "DOTS/ECS", "Shader Graph"], right: ["Data containers without MonoBehaviour overhead", "Async asset loading with memory management", "High-performance data-oriented architecture", "Visual node-based shader creation"] }, _answer: [0, 1, 2, 3], explanation: "ScriptableObjects store data (items, stats) without scene dependency. Addressables manage asset bundles and loading. DOTS/ECS enables massive entity counts with cache-friendly memory. Shader Graph creates shaders visually.", articleSlug: "unity-game-engine-advanced", tags: ["ScriptableObject", "DOTS", "Addressables"] },
        { id: "uge-q009", part: 9, difficulty: "advanced", type: "architecture", question: "You're building a multiplayer Unity game with 50 players. Which networking architecture?", scenario: "Action RPG with real-time combat. Need: responsive movement, authoritative hit detection, 50 concurrent players per server.", options: [{ label: "Unity Netcode for GameObjects (NGO) with client-authoritative movement", tradeoffs: ["Fast iteration", "Built-in Unity", "Cheat-vulnerable", "Limited to ~20 players performant"] }, { label: "Dedicated server (headless Unity) with server-authoritative physics", tradeoffs: ["Anti-cheat", "Deterministic", "Server hosting cost", "Input lag needs prediction"] }, { label: "Photon PUN relay with room-based architecture", tradeoffs: ["Easy setup", "Relay latency", "50 player limit per room", "No server authority"] }, { label: "Custom ECS server (non-Unity) with thin Unity client", tradeoffs: ["Maximum performance", "Server scales to 200+", "No visual debugging", "Separate codebases"] }], _answer: 1, explanation: "For competitive multiplayer with anti-cheat requirements, server-authoritative is necessary. Headless Unity server runs the same game logic, validates all actions, and rejects cheating. Client-side prediction masks latency. NGO or Fish-Net for transport.", articleSlug: "unity-game-engine-networking", tags: ["multiplayer", "networking", "server-authoritative"] },
        { id: "uge-q010", part: 10, difficulty: "intermediate", type: "ethical", question: "Unity changed its pricing model to include a per-install fee (Runtime Fee). Is this ethical for the game development ecosystem?", scenario: "In 2023, Unity announced a per-install fee for games exceeding revenue/install thresholds. Developers who built studios around Unity's original terms faced unexpected costs. After backlash, terms were modified.", options: [{ label: "Unity has the right to change pricing — it's their platform", framework: "Business prerogative — companies set their own terms" }, { label: "Retroactive pricing changes violate implicit contracts with existing developers", framework: "Contract ethics — terms at time of adoption should be honored" }, { label: "Per-install fees align platform incentives with developer success", framework: "Alignment — Unity earns when developers earn" }, { label: "Engine pricing should be open-source or perpetual-license to prevent platform risk", framework: "Developer sovereignty — eliminate vendor dependency" }], _answer: 1, explanation: "The backlash centered on retroactive application: developers made business decisions (chose Unity) based on existing terms. Changing terms for already-shipped games violated trust. Unity partially reversed, but the incident accelerated Godot/Unreal adoption.", articleSlug: "unity-game-engine-business", tags: ["pricing", "ethics", "platform risk"] }
    ]
});

