const roboticsAutomation = buildQuiz({
    series: "robotics-automation",
    title: "Robotics & Automation",
    salt: "robot-auto-26",
    totalParts: 18,
    questions: [
        { id: "ra-q001", part: 1, difficulty: "beginner", type: "mcq", question: "What are the three fundamental components of a robotic system?", options: ["Motor, gear, wheel", "Sensor, controller, actuator", "Camera, CPU, display", "Power, frame, software"], _answer: 1, explanation: "Every robot has: Sensors (perceive environment — cameras, LIDAR, encoders), Controller (process data, make decisions — MCU/CPU), Actuators (act on environment — motors, grippers, pneumatics).", articleSlug: "robotics-automation-fundamentals", tags: ["fundamentals", "components"] },
        { id: "ra-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "A 6-DOF robotic arm can reach any point in its workspace with any orientation.", _answer: true, explanation: "6 degrees of freedom (3 position + 3 orientation) is the minimum needed to place an end-effector at any reachable point with any orientation. Fewer DOF restricts orientation options. More DOF adds redundancy (beneficial for obstacle avoidance).", articleSlug: "robotics-automation-kinematics", tags: ["DOF", "kinematics"] },
        { id: "ra-q003", part: 3, difficulty: "intermediate", type: "fill-blank", question: "A PID controller's three terms stand for Proportional, Integral, and ___.", _answer: "Derivative", acceptAlso: ["derivative", "differential", "D"], explanation: "PID: P (proportional to current error — corrects now), I (integral of past errors — eliminates steady-state offset), D (derivative of error — predicts future, dampens oscillation). Most common industrial controller.", articleSlug: "robotics-automation-pid-control", tags: ["PID", "control"] },
        { id: "ra-q004", part: 4, difficulty: "advanced", type: "code-output", question: "A robot wheel encoder has 1000 counts per revolution. The wheel diameter is 10cm. After 5000 counts, how far has the robot traveled?", code: "counts = 5000\ncounts_per_rev = 1000\nwheel_diameter_cm = 10\n\nrevolutions = counts / counts_per_rev  # 5\ndistance = revolutions * 3.14159 * wheel_diameter_cm\nprint(f'{distance:.1f} cm')", _answer: "157.1 cm", acceptAlso: ["157.1", "157 cm", "1.57 m"], explanation: "5000/1000 = 5 revolutions. Distance = 5 × π × 10cm = 5 × 31.42cm = 157.1cm. Wheel odometry is fundamental for mobile robot localization (dead reckoning).", articleSlug: "robotics-automation-odometry", tags: ["odometry", "encoders"] },
        { id: "ra-q005", part: 5, difficulty: "advanced", type: "scenario", question: "Your mobile robot's SLAM (localization) drifts 2° per minute in a warehouse. After 30 minutes, it's 1.5m off course. What's the best correction strategy?", scenario: { context: "Warehouse AGV (Automated Guided Vehicle). LIDAR SLAM. No GPS indoors.", metrics: { "Drift rate": "2°/min rotational", "After 30 min": "1.5m positional error", "Environment": "Repetitive shelving (symmetric)", "Speed": "1 m/s" } }, options: ["Add floor fiducial markers (QR codes) at known positions for absolute correction", "Use IMU fusion to reduce rotational drift", "Increase LIDAR scan rate from 10Hz to 40Hz", "Add UWB beacons for absolute position reference"], _answer: 0, explanation: "Floor fiducial markers (AprilTags, QR codes) at known positions provide absolute position reset at low cost. When the robot drives over one, drift is instantly corrected. UWB works but is more expensive. The root cause (repetitive shelving confusing SLAM) is hard to fix otherwise.", articleSlug: "robotics-automation-slam", tags: ["SLAM", "localization", "fiducials"] },
        { id: "ra-q006", part: 6, difficulty: "advanced", type: "debug", question: "A robotic arm overshoots its target position and oscillates before settling. The PID gains are Kp=10, Ki=2, Kd=0.1. Which gain needs adjustment?", code: "PID Controller Response:\n- Target: 90 degrees\n- Overshoot: reaches 105° before correcting\n- Oscillates: 105° → 82° → 95° → 88° → 91° → 89.5° → 90°\n- Settling time: 3 seconds (requirement: < 1 second)\n\nKp = 10, Ki = 2, Kd = 0.1", options: ["Kp too high — reduce proportional gain to decrease overshoot", "Kd too low — increase derivative gain to dampen oscillation", "Ki too high — integral windup causing continued correction past target", "Both Kd too low and Ki too high — increase damping, reduce integral accumulation"], _answer: 3, explanation: "Oscillation with slow settling indicates: (1) Kd is too low — not enough damping (derivative predicts and slows approach), (2) Ki accumulated error during overshoot keeps pushing past target (integral windup). Fix: increase Kd to 1.0+, reduce Ki to 0.5, or add integral anti-windup.", articleSlug: "robotics-automation-pid-tuning", tags: ["PID tuning", "oscillation"] },
        { id: "ra-q007", part: 7, difficulty: "intermediate", type: "matching", question: "Match each sensor to its typical robotics application:", pairs: { left: ["LIDAR", "IMU (Inertial Measurement Unit)", "Force/Torque sensor", "Depth camera (RGB-D)"], right: ["2D/3D mapping and obstacle detection (up to 100m)", "Orientation tracking and dead reckoning between sensor updates", "Detecting contact force for manipulation and assembly", "Close-range 3D perception for object recognition and grasping"] }, _answer: [0, 1, 2, 3], explanation: "LIDAR: long-range mapping (autonomous cars). IMU: fast orientation updates between slower sensors. Force/torque: delicate manipulation (assembly robots). RGB-D: close-range object understanding (pick-and-place).", articleSlug: "robotics-automation-sensors", tags: ["LIDAR", "IMU", "sensors"] },
        { id: "ra-q008", part: 8, difficulty: "advanced", type: "ordering", question: "Arrange the ROS2 (Robot Operating System) communication stack from lowest to highest level:", items: ["DDS (Data Distribution Service) middleware", "ROS2 client library (rclpy/rclcpp)", "Application node logic", "Topic/Service/Action interfaces", "rmw (ROS middleware) abstraction layer"], _answer: ["DDS (Data Distribution Service) middleware", "rmw (ROS middleware) abstraction layer", "ROS2 client library (rclpy/rclcpp)", "Topic/Service/Action interfaces", "Application node logic"], explanation: "ROS2 stack: DDS (transport layer, handles discovery/QoS) → rmw (abstracts DDS vendor) → rcl/rclcpp/rclpy (client libraries) → Topics/Services/Actions (communication patterns) → Your code (nodes).", articleSlug: "robotics-automation-ros2", tags: ["ROS2", "DDS", "architecture"] },
        { id: "ra-q009", part: 9, difficulty: "advanced", type: "calculation", question: "A 6-DOF robotic arm needs to move its end-effector 50cm in 2 seconds along a straight line (trapezoidal velocity profile: 0.5s accel, 1s cruise, 0.5s decel). What's the cruise velocity?", formula: "Distance = (0.5 × v × t_accel) + (v × t_cruise) + (0.5 × v × t_decel)", _answer: 0.333, unit: "m/s", tolerance: 0.01, explanation: "0.5m = (0.5 × v × 0.5) + (v × 1.0) + (0.5 × v × 0.5) = 0.25v + v + 0.25v = 1.5v. So v = 0.5/1.5 = 0.333 m/s. The trapezoidal profile is standard for smooth motion without jerky starts/stops.", articleSlug: "robotics-automation-motion-planning", tags: ["trajectory", "trapezoidal profile"] },
        { id: "ra-q010", part: 10, difficulty: "advanced", type: "ethical", question: "Should autonomous robots in warehouses be required to slow down or stop when humans enter their operating area, even if it reduces productivity by 30%?", scenario: "Amazon warehouses use Kiva robots sharing space with human pickers. Full-speed autonomous operation could increase throughput 30% but carries collision risk. Current approach: segregated zones with speed reduction near humans.", options: [{ label: "Maximum safety — robots stop completely when any human is within 5m", framework: "Zero harm — human safety is absolute priority" }, { label: "Current approach is fine — speed reduction + segregated zones balances productivity and safety", framework: "Balanced — acceptable risk with mitigation" }, { label: "Invest in better sensing/prediction so robots can operate at full speed safely near humans", framework: "Technology solution — solve with better AI, not restrictions" }, { label: "Remove humans from robot areas entirely — full automation or full human zones", framework: "Separation — eliminate the interaction entirely" }], _answer: 1, explanation: "ISO 15066 (collaborative robots safety) establishes the current approach: speed/force limits that reduce injury severity to acceptable levels when contact occurs. Full segregation eliminates flexibility; full speed is too risky with current sensing reliability.", articleSlug: "robotics-automation-safety", tags: ["safety", "human-robot interaction", "ISO 15066"] }
    ]
});

