const salesMastery = buildQuiz({
    series: "sales-mastery",
    title: "Sales Mastery",
    salt: "sales-mstr-26",
    totalParts: 18,
    questions: [
        { id: "sm-q001", part: 1, difficulty: "beginner", type: "mcq", question: "In the BANT framework, what does the 'A' stand for?", options: ["Action", "Authority", "Agreement", "Assessment"], _answer: 1, explanation: "BANT: Budget (can they afford it?), Authority (are they the decision-maker?), Need (do they have a genuine problem?), Timeline (when do they need a solution?). Authority qualification prevents selling to people who can't sign.", articleSlug: "sales-mastery-fundamentals-psychology", tags: ["BANT", "qualification"] },
        { id: "sm-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "The best salespeople talk more than they listen during discovery calls.", _answer: false, explanation: "Top performers have a talk:listen ratio of 43:57 (Gong.io research). During discovery, the ratio should be even more listening-heavy (30:70). Active listening uncovers pain points, builds trust, and provides information to tailor the pitch.", articleSlug: "sales-mastery-discovery", tags: ["discovery", "listening"] },
        { id: "sm-q003", part: 3, difficulty: "intermediate", type: "fill-blank", question: "The sales methodology SPIN stands for Situation, Problem, Implication, and ___.", _answer: "Need-payoff", acceptAlso: ["need-payoff", "Need-Payoff", "Need Payoff", "need payoff"], explanation: "SPIN Selling (Neil Rackham, 1988): Situation questions (context), Problem questions (pain), Implication questions (consequence of inaction), Need-payoff questions (value of solving). Moves from information gathering to value creation.", articleSlug: "sales-mastery-spin-selling", tags: ["SPIN", "methodology"] },
        { id: "sm-q004", part: 4, difficulty: "advanced", type: "scenario", question: "You're in a final presentation for a $500K enterprise deal. The CFO raises a price objection: 'Your competitor is 30% cheaper.' What's your best response?", scenario: { context: "B2B SaaS. Your solution: $500K/year. Competitor: $350K/year. Your product has better analytics and support.", metrics: { "Your price": "$500K", "Competitor": "$350K", "Your NPS": "72", "Competitor NPS": "34", "Implementation": "4 weeks vs 12 weeks" } }, options: ["Offer a 20% discount to match closer to competitor pricing", "Acknowledge the difference and quantify your ROI advantage (faster implementation saves $200K in productivity)", "Ask 'What's more important to your team — initial cost or total cost of ownership over 3 years?'", "Suggest a smaller initial deployment to prove value before full commitment"], _answer: 2, explanation: "Reframing from price to value: this question shifts the conversation from line-item cost to business outcome. It forces the CFO to consider implementation time, support quality, and long-term TCO — where you win. Never lead with discounting (devalues your product).", articleSlug: "sales-mastery-objection-handling", tags: ["objections", "pricing", "value selling"] },
        { id: "sm-q005", part: 5, difficulty: "intermediate", type: "ordering", question: "Arrange the enterprise sales cycle stages in typical order:", items: ["Negotiation and closing", "Discovery and qualification", "Prospecting and outreach", "Proposal and demo", "Onboarding and expansion"], _answer: ["Prospecting and outreach", "Discovery and qualification", "Proposal and demo", "Negotiation and closing", "Onboarding and expansion"], explanation: "Enterprise B2B cycle: Prospect (identify leads) → Discover (understand needs, qualify BANT) → Present (tailored demo + proposal) → Negotiate (terms, pricing) → Close and onboard. Average cycle: 3-9 months.", articleSlug: "sales-mastery-enterprise-sales", tags: ["sales cycle", "enterprise"] },
        { id: "sm-q006", part: 6, difficulty: "advanced", type: "calculation", question: "A sales rep has 100 leads, 25% qualify, 40% of qualified leads take a demo, and 30% of demos close. Average deal size is $50K. What's the pipeline value?", formula: "Expected revenue = Leads × Qualify_rate × Demo_rate × Close_rate × Deal_size", _answer: 150000, unit: "$", tolerance: 0, explanation: "100 × 0.25 × 0.40 × 0.30 × $50,000 = 100 × 0.03 × $50,000 = $150,000 expected pipeline value. This rep needs ~7× pipeline coverage (typical B2B) to reliably hit a $150K quota.", articleSlug: "sales-mastery-pipeline", tags: ["pipeline", "forecasting"] },
        { id: "sm-q007", part: 7, difficulty: "advanced", type: "matching", question: "Match each closing technique to its description:", pairs: { left: ["Assumptive close", "Summary close", "Urgency close", "Puppy dog close"], right: ["Proceed as if the prospect has already decided yes", "Recap all agreed benefits before asking for commitment", "Time-limited offer creating FOMO", "Let them try the product — harder to return than to keep"] }, _answer: [0, 1, 2, 3], explanation: "Assumptive: 'Should I send the contract to you or your CFO?' Summary: 'So we've agreed on X, Y, Z — shall we move forward?' Urgency: 'This pricing expires Friday.' Puppy dog: free trial/POC that creates stickiness.", articleSlug: "sales-mastery-closing", tags: ["closing", "techniques"] },
        { id: "sm-q008", part: 8, difficulty: "advanced", type: "debug", question: "A salesperson consistently hits 80% of quota. Their activity metrics look good. Find the gap:", code: "Monthly metrics:\n- Calls made: 200 (target: 150) ✓\n- Emails sent: 500 (target: 400) ✓\n- Meetings booked: 20 (target: 15) ✓\n- Demos delivered: 12 (target: 10) ✓\n- Proposals sent: 8 (target: 6) ✓\n- Deals closed: 2 (target: 4) ✗\n- Average deal size: $25K (target: $50K) ✗\n- Win rate: 25% (team avg: 35%)", options: ["Low win rate (25% vs 35%) — likely not qualifying prospects well enough or losing in negotiation", "Small deal sizes ($25K vs $50K target) — selling to wrong tier of customer or discounting too much", "Both: poor qualification leads to smaller, less likely deals — the root cause is discovery quality", "Activity is too high — quantity over quality, not spending enough time per opportunity"], _answer: 2, explanation: "The pattern reveals: high activity + low close rate + small deals = poor qualification. This rep fills the pipeline with unqualified or wrong-tier prospects. They need better discovery (BANT/MEDDIC) to focus on larger, more likely deals rather than more activity.", articleSlug: "sales-mastery-diagnostics", tags: ["qualification", "pipeline quality"] },
        { id: "sm-q009", part: 9, difficulty: "intermediate", type: "mcq", question: "What does 'social selling' primarily involve?", options: ["Selling products on social media marketplaces", "Using social media to build relationships and trust with prospects before formal outreach", "Running paid ads on LinkedIn and Facebook", "Posting product catalogs on Instagram"], _answer: 1, explanation: "Social selling is building credibility and relationships through content sharing, engaging with prospects' posts, and providing value on platforms like LinkedIn — warming leads before cold outreach. Social Selling Index (SSI) correlates with quota attainment.", articleSlug: "sales-mastery-social-selling", tags: ["social selling", "LinkedIn"] },
        { id: "sm-q010", part: 10, difficulty: "advanced", type: "ethical", question: "Should salespeople be transparent about product limitations when they know a competitor handles a specific use case better?", scenario: "Your CRM lacks a feature the prospect mentioned is important. Your competitor has it. You could deflect, promise it's on the roadmap, or be honest. The deal is worth $200K ARR.", options: [{ label: "Be transparent — honesty builds long-term trust and prevents churn", framework: "Trust-based selling — relationship over transaction" }, { label: "Deflect to strengths — it's not lying to focus on where you win", framework: "Competitive positioning — sell your value, not their gaps" }, { label: "Promise it's on the roadmap even if uncertain — secure the deal", framework: "Optimistic — most roadmap items eventually ship" }, { label: "Acknowledge the gap AND show the overall ROI still favors your solution", framework: "Consultative — honest assessment with full context" }], _answer: 3, explanation: "Best practice: acknowledge ('You're right, we don't have X today'), then contextualize ('However, our advantages in A, B, C deliver 3× ROI even without X'). This builds trust and often wins: prospects respect honesty over perfection. Hiding gaps causes post-sale churn.", articleSlug: "sales-mastery-ethics", tags: ["ethics", "honesty", "trust"] }
    ]
});

